import * as vscode from 'vscode';
import * as http from 'http';
import axios from 'axios';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { spawn, spawnSync } from 'child_process';

// ============================================================
// Security helpers
// ============================================================

const MAX_HTTP_BODY = 5 * 1024 * 1024; // 5MB cap on /api/* request bodies
const MAX_STREAM_BUFFER = 2 * 1024 * 1024; // 2MB cap on per-stream line buffer
const MAX_FILE_NAME_LEN = 200;

/**
 * Run a git subcommand with argv form (no shell interpolation).
 * Returns stdout on success, throws on failure. Never blocks longer than `timeout`.
 */
function gitExec(args: string[], cwd: string, timeout = 15000): string {
    const res = spawnSync('git', args, {
        cwd,
        encoding: 'utf-8',
        timeout,
        env: { ...process.env, GIT_TERMINAL_PROMPT: '0' } // never block on credential prompt
    });
    if (res.error) throw res.error;
    if (res.status !== 0) {
        const err: any = new Error(`git ${args[0]} failed: ${res.stderr?.trim() || 'unknown'}`);
        err.code = res.status;
        err.stderr = res.stderr;
        throw err;
    }
    return res.stdout || '';
}

/** Same as gitExec but swallows errors and returns null. */
function gitExecSafe(args: string[], cwd: string, timeout = 15000): string | null {
    try { return gitExec(args, cwd, timeout); }
    catch { return null; }
}

/**
 * Resolve `relPath` against `root` and confirm the result stays within `root`.
 * Returns absolute path on success, null if traversal is detected.
 */
function safeResolveInside(root: string, relPath: string): string | null {
    if (typeof relPath !== 'string' || relPath.length === 0) return null;
    const resolvedRoot = path.resolve(root);
    const abs = path.resolve(resolvedRoot, relPath);
    const rel = path.relative(resolvedRoot, abs);
    if (rel.startsWith('..') || path.isAbsolute(rel)) return null;
    return abs;
}

/* v2.89.93 έΑΦ ΉηΡΉειΈκεΉγ┤ Ά▓╜Έκε ΊΧ┤ΉΕζ. ΉΓυΉγσΉηΡΆ░Α "~/Documents/foo.md", "$HOME/x",
   ΉιΙΈΝΑΆ▓╜Έκε ΈςρΈΣΡ ΉηΡΉΩ░ΉΛνΈθ╜Ά▓Ν ΉΓυΉγσΊΧι ΉΙα ΉηΙΉΨ┤ΉΧ╝ ΊΧρ. ΉαΙΉιΕ safeResolveInsideΈΛΦ
   ΉδΝΊΒυΉΛνΊΟαΉζ┤ΉΛν ΉΧΙΉΩΡ Ά░ΘΊαΑΉΕε "ΈΓ┤ ΈΣΡΈΘΝ ΊΠ┤ΈΞΦ ΊΟ╕ΉπΣΊΧ┤" Ά░βΉζΑ ΉηΡΉΩ░ΉΛνΈθυΉγ┤ ΉγΦΆ╡υΈξ╝
   ΈΜν Ή░ρΈΜρΊΨΙΉζΝ. Ήζ┤Ήιε expand έΗΤ absolute έΗΤ ΉΜεΉΛνΊΖε Έ│┤Ία╕Ά▓╜ΈκεΈπΝ Ή░ρΈΜρ.
   - "~" / "~/foo" έΗΤ home ΊβΧΉηξ
   - "$HOME/x", "${HOME}/x" έΗΤ env ΊβΧΉηξ (ΉΧΙΉιΕ Έ│ΑΉΙαΈπΝ)
   - ΉιΙΈΝΑΆ▓╜Έκε Ά╖╕ΈΝΑΈκε
   - ΉΔΒΈΝΑΆ▓╜Έκε έΗΤ root Ά╕░ΉνΑ resolve
   ΉΜεΉΛνΊΖε Ά▓╜Έκε(/etc, /System, /usr/bin, /bin, /sbin, %WINDIR%) ΈπΝ Ή░ρΈΜρ. */
const _SYSTEM_PATH_BLOCKLIST = [
    '/etc', '/System', '/usr/bin', '/usr/sbin', '/bin', '/sbin', '/var/db',
    '/private/etc', '/private/var/db',
];
function _resolveFlexiblePath(input: string, root: string): { abs: string; reason?: string } | null {
    if (typeof input !== 'string') return null;
    let s = input.trim();
    if (!s) return null;
    /* v2.89.101 έΑΦ env var expansion. WindowsΉΩΡΉΕι process.env.HOMEΉζ┤ Έ╣ΕΉΨ┤ΉηΙΈΛΦ
       Ά▓╜Ήγ░Ά░Α ΊζΦΊΧ┤ΉΕε, HOMEΉζΕ os.homedir()Έκε Ά░ΧΉιε fallback. USERΈΛΦ USERNAMEΉΩΡΉΕε
       Ήζ╜Ά│ι, TMPΈΛΦ TMPDIR/TEMP/TMP ΉΙεΉε╝Έκε ΉΜεΈΠΕ. */
    s = s.replace(/\$\{?(HOME|USER|USERNAME|TMPDIR|TEMP|TMP|APPDATA|LOCALAPPDATA|USERPROFILE|HOMEDRIVE|HOMEPATH)\}?/g, (_m, k) => {
        if (k === 'HOME') return process.env.HOME || os.homedir();
        if (k === 'USER' || k === 'USERNAME') return process.env.USER || process.env.USERNAME || os.userInfo().username || _m;
        if (k === 'TMPDIR' || k === 'TEMP' || k === 'TMP') return process.env.TMPDIR || process.env.TEMP || process.env.TMP || os.tmpdir();
        const v = process.env[k]; return v || _m;
    });
    /* tilde expansion */
    if (s === '~') s = os.homedir();
    else if (s.startsWith('~/') || s.startsWith('~\\')) s = path.join(os.homedir(), s.slice(2));
    /* absolute or relative έΑΦ path.normalizeΈκε Ία╝ΉηυΈΡε ΉΛυΈηαΉΜε ΊΗ╡Ήζ╝ */
    let abs = path.isAbsolute(s) ? path.resolve(s) : path.resolve(root, s);
    abs = path.normalize(abs);
    /* ΉΜεΉΛνΊΖε Ά▓╜Έκε Ή░ρΈΜρ έΑΦ Ά░ΑΈ▓╝Ήγ┤ Έ│┤Ία╕. ΉΓυΉγσΉηΡ ΊβΙ┬╖Έυ╕ΉΕε┬╖Ήβ╕Έ╢Α ΈΦΦΉΛνΊΒυΈΛΦ ΉηΡΉει. */
    for (const blocked of _SYSTEM_PATH_BLOCKLIST) {
        if (abs === blocked || abs.startsWith(blocked + path.sep)) {
            return { abs, reason: `ΉΜεΉΛνΊΖε Έ│┤Ία╕ Ά▓╜Έκε(${blocked})ΉΩΡΈΛΦ ΉΥ░ΉπΑ ΉΧΛΉΛ╡ΈΜΙΈΜν. ΉΓυΉγσΉηΡ ΊβΙ/ΉδΝΊΒυΉΛνΊΟαΉζ┤ΉΛν ΉΧΙΉζα Ά▓╜ΈκεΈξ╝ ΉπΑΉιΧΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.` };
        }
    }
    /* Windows: C:\Windows / C:\Program Files / C:\ProgramData Έ│┤Ία╕ */
    if (process.platform === 'win32') {
        const upper = abs.toUpperCase();
        const winDirs = [
            (process.env.WINDIR || 'C:\\WINDOWS').toUpperCase(),
            (process.env.PROGRAMFILES || 'C:\\PROGRAM FILES').toUpperCase(),
            (process.env['PROGRAMFILES(X86)'] || 'C:\\PROGRAM FILES (X86)').toUpperCase(),
            (process.env.PROGRAMDATA || 'C:\\PROGRAMDATA').toUpperCase(),
            (process.env.SYSTEMROOT || 'C:\\WINDOWS').toUpperCase(),
        ];
        for (const w of winDirs) {
            if (upper === w || upper.startsWith(w + path.sep)) {
                return { abs, reason: `ΉΜεΉΛνΊΖε Έ│┤Ία╕ Ά▓╜Έκε(${w})ΉΩΡΈΛΦ ΉΥ░ΉπΑ ΉΧΛΉΛ╡ΈΜΙΈΜν. Documents┬╖Desktop┬╖ΈΜνΈξ╕ ΉΓυΉγσΉηΡ ΊΠ┤ΈΞΦΈκε ΉπΑΉιΧΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.` };
            }
        }
    }
    return { abs };
}

/* v2.89.104 έΑΦ Claude Ήζ╡ΉΛνΊΖΡΉΖα Ία╕Ίβα unified diff. edit_file ΊδΕ Έ│ΑΆ▓╜ hunkΈξ╝
   ┬▒3ΉνΕ Ή╗ρΊΖΞΉΛνΊΛ╕Έκε ΊΣεΉΜε. Έ│ΑΆ▓╜ ΉΩΗΉε╝Έσ┤ Έ╣Ι Έυ╕ΉηΡΉΩ┤ Έ░αΊβα.
   ΉΧΝΆ│ιΈουΉοα: line-by-line LCSΈΛΦ Έ╣ΕΉγσ ΊΒ╝ έΗΤ ΈΜρΉΙε chunk Έ╣ΕΆ╡Ρ(Patience ΉΛνΊΔΑΉζ╝ Ά░ΕΉΗΝΊβΦ).
   ΈΝΑΈ╢ΑΈ╢Ε edit_fileΉζΑ ΉηΣΉζΑ ΉαΒΉΩφΈπΝ Έ░ΦΆ╛╕ΈψΑΈκε Ή╢σΈ╢ΕΊηΙ ΉιΧΊβΧ. ΈΕΙΈυ┤ Ά╕╕Έσ┤ Ή▓τ 50ΉνΕΈπΝ. */
function _renderUnifiedDiff(before: string, after: string, ctx: number = 3): string {
    if (before === after) return '';
    const a = before.split('\n');
    const b = after.split('\n');
    /* Ά│╡ΊΗ╡ prefix┬╖suffix ΉππΆ▓Ν ΉΜζΈ│Ε */
    let prefixLen = 0;
    while (prefixLen < a.length && prefixLen < b.length && a[prefixLen] === b[prefixLen]) prefixLen++;
    let suffixLen = 0;
    while (
        suffixLen < a.length - prefixLen &&
        suffixLen < b.length - prefixLen &&
        a[a.length - 1 - suffixLen] === b[b.length - 1 - suffixLen]
    ) suffixLen++;
    const aChanged = a.slice(prefixLen, a.length - suffixLen);
    const bChanged = b.slice(prefixLen, b.length - suffixLen);
    const ctxStart = Math.max(0, prefixLen - ctx);
    const ctxEndA = Math.min(a.length, a.length - suffixLen + ctx);
    const ctxEndB = Math.min(b.length, b.length - suffixLen + ctx);
    const out: string[] = [];
    out.push(`@@ -${ctxStart + 1},${ctxEndA - ctxStart} +${ctxStart + 1},${ctxEndB - ctxStart} @@`);
    /* ΉΧη Ή╗ρΊΖΞΉΛνΊΛ╕ */
    for (let i = ctxStart; i < prefixLen; i++) out.push(' ' + a[i]);
    /* Έ│ΑΆ▓╜ Έ╢ΑΈ╢Ε: ΉΓφΉιε έΗΤ Ή╢ΦΆ░Α */
    for (const line of aChanged) out.push('-' + line);
    for (const line of bChanged) out.push('+' + line);
    /* ΈΤν Ή╗ρΊΖΞΉΛνΊΛ╕ */
    for (let i = a.length - suffixLen; i < ctxEndA; i++) out.push(' ' + a[i]);
    /* 50ΉνΕ cap */
    if (out.length > 52) {
        return out.slice(0, 52).join('\n') + '\n... (' + (out.length - 52) + 'ΉνΕ ΈΞΦ ΉηΙΉζΝ)';
    }
    return out.join('\n');
}

/* v2.89.104 έΑΦ glob ΈπνΉ╣φ (Ά░ΕΈΜρ Έ▓ΕΉιΕ). `*`, `**`, `?` ΉπΑΉδΡ. node-glob ΉζαΉκ┤ΉΕ▒ ΉΧΙ Ή╢ΦΆ░Α.
   `**`ΈΛΦ 0Ά░ε Ήζ┤ΉΔΒΉζα ΈΦΦΈιΚΊΗιΈου, `*`ΈΛΦ ΉΛυΈηαΉΜε ΉιεΉβ╕ 0+, `?`ΈΛΦ ΈΜρΉζ╝ Έυ╕ΉηΡ.
   ΉηυΆ╖Α ΈΦΦΈιΚΊΗιΈου ΉδΝΊΒυ + ΊΝρΊΕ┤ ΈπνΉ╣φ. Ά▓░Ά│╝ΈΛΦ Ή╡εΈΝΑ 200Ά░ε. */
function _globMatch(pattern: string, root: string, maxResults: number = 200): string[] {
    const re = _globToRegex(pattern);
    const results: string[] = [];
    const skipDirs = new Set(['node_modules', '.git', '.next', 'dist', 'out', 'build', '.cache', '__pycache__', '.venv', 'venv', '.idea', '.vscode']);
    function walk(dir: string, depth: number) {
        if (results.length >= maxResults || depth > 12) return;
        let entries: fs.Dirent[];
        try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch { return; }
        for (const e of entries) {
            if (results.length >= maxResults) return;
            if (e.name.startsWith('.git')) continue;
            const full = path.join(dir, e.name);
            if (e.isDirectory()) {
                if (skipDirs.has(e.name)) continue;
                walk(full, depth + 1);
            } else if (e.isFile()) {
                const rel = path.relative(root, full).split(path.sep).join('/');
                if (re.test(rel)) results.push(rel);
            }
        }
    }
    walk(root, 0);
    return results;
}
function _globToRegex(pattern: string): RegExp {
    /* `**`Έξ╝ placeholderΈκε escape, ΈΓαΈρ╕ΉπΑ Έ│ΑΊβα ΊδΕ Έ│╡ΉδΡ */
    let re = pattern.replace(/[.+^${}()|[\]\\]/g, '\\$&');
    re = re.replace(/\*\*\//g, '__GLOBSTAR_SLASH__');
    re = re.replace(/\*\*/g, '__GLOBSTAR__');
    re = re.replace(/\*/g, '[^/]*');
    re = re.replace(/\?/g, '[^/]');
    re = re.replace(/__GLOBSTAR_SLASH__/g, '(?:.*/)?');
    re = re.replace(/__GLOBSTAR__/g, '.*');
    return new RegExp('^' + re + '$', 'i');
}

/* v2.89.104 έΑΦ grep: ΊΝΝΉζ╝ ΈΓ┤ΉγσΉΩΡΉΕε ΊΝρΊΕ┤ Ά▓ΑΉΔΚ. case-insensitive Ά╕░Έ│╕.
   Ά▓░Ά│╝ΈΛΦ ΊΝΝΉζ╝Έ│ΕΈκε Έυ╢ΉΨ┤ΉΕε line:N ΈπνΉ╣αΈζ╝Ήζ╕ Έ░αΊβα. Ή╡εΈΝΑ 50ΊΝΝΉζ╝┬╖ΊΝΝΉζ╝ΈΜ╣ 10ΈπνΉ╣α. */
function _grepFiles(pattern: string, root: string, fileGlob?: string): { file: string; matches: { line: number; text: string }[] }[] {
    let regex: RegExp;
    try { regex = new RegExp(pattern, 'i'); }
    catch { return []; }
    const fileRe = fileGlob ? _globToRegex(fileGlob) : null;
    const results: { file: string; matches: { line: number; text: string }[] }[] = [];
    const skipDirs = new Set(['node_modules', '.git', '.next', 'dist', 'out', 'build', '.cache', '__pycache__', '.venv', 'venv', '.idea', '.vscode']);
    const MAX_FILES = 50;
    const MAX_PER_FILE = 10;
    const MAX_FILE_BYTES = 1024 * 1024;  /* 1MB Ή┤ΙΆ│╝ ΊΝΝΉζ╝ ΉΛνΊΓ╡ */
    function walk(dir: string, depth: number) {
        if (results.length >= MAX_FILES || depth > 12) return;
        let entries: fs.Dirent[];
        try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch { return; }
        for (const e of entries) {
            if (results.length >= MAX_FILES) return;
            if (e.name.startsWith('.git')) continue;
            const full = path.join(dir, e.name);
            if (e.isDirectory()) {
                if (skipDirs.has(e.name)) continue;
                walk(full, depth + 1);
            } else if (e.isFile()) {
                const rel = path.relative(root, full).split(path.sep).join('/');
                if (fileRe && !fileRe.test(rel)) continue;
                try {
                    const stat = fs.statSync(full);
                    if (stat.size > MAX_FILE_BYTES) continue;
                    const buf = fs.readFileSync(full);
                    /* Έ░ΦΉζ┤ΈΕΙΈου Έ╣ιΈξ╕ Ή▓┤ΊΒυ */
                    if (buf.slice(0, 512).includes(0)) continue;
                    const content = buf.toString('utf-8');
                    const lines = content.split('\n');
                    const matches: { line: number; text: string }[] = [];
                    for (let i = 0; i < lines.length; i++) {
                        if (regex.test(lines[i])) {
                            matches.push({ line: i + 1, text: lines[i].slice(0, 200) });
                            if (matches.length >= MAX_PER_FILE) break;
                        }
                    }
                    if (matches.length > 0) results.push({ file: rel, matches });
                } catch { /* skip */ }
            }
        }
    }
    walk(root, 0);
    return results;
}

/* v2.89.93 έΑΦ OS ΊΝΝΉζ╝ Ήζ╡ΉΛνΊΦΝΈκεΈθυΈκε ΊΝΝΉζ╝/ΊΠ┤ΈΞΦ ΉΩ┤Ά╕░ (Finder ┬╖ Windows Explorer ┬╖
   Linux GNOME Files). Ά▓░Ά│╝ ΈσΦΉΜεΉπΑΈξ╝ Έ░αΊβαΊΧ┤ΉΕε Ία╕Ή╢εΉ▓αΆ░Α ΉΓυΉγσΉηΡΉΩΡΆ▓Ν Έ│┤ΉΩυΉνΕ ΉΙα ΉηΙΆ▓Ν. */
function _revealInOsExplorer(targetPath: string): { ok: boolean; message: string } {
    try {
        if (!fs.existsSync(targetPath)) {
            return { ok: false, message: `Ήκ┤ΉηυΊΧαΉπΑ ΉΧΛΈΛΦ Ά▓╜Έκε: ${targetPath}` };
        }
        if (process.platform === 'darwin') {
            spawn('open', ['-R', targetPath], { detached: true, stdio: 'ignore' }).unref();
        } else if (process.platform === 'win32') {
            spawn('explorer.exe', ['/select,', targetPath], { detached: true, stdio: 'ignore' }).unref();
        } else {
            const dir = fs.statSync(targetPath).isDirectory() ? targetPath : path.dirname(targetPath);
            spawn('xdg-open', [dir], { detached: true, stdio: 'ignore' }).unref();
        }
        return { ok: true, message: `ΏθΩΓ Ήζ╡ΉΛνΊΦΝΈκεΈθυ ΉΩ┤Έο╝: ${targetPath}` };
    } catch (e: any) {
        return { ok: false, message: `Ήζ╡ΉΛνΊΦΝΈκεΈθυ ΉΩ┤Ά╕░ ΉΜνΊΝρ: ${e?.message || e}` };
    }
}

/* v2.89.93 έΑΦ Ά╕░Έ│╕ ΉΧ▒Ήε╝Έκε ΊΝΝΉζ╝ ΉΩ┤Ά╕░ (Ήζ┤Έψ╕ΉπΑ┬╖PDF┬╖Ήδ╣ΊΟαΉζ┤ΉπΑ┬╖.docx ΈΥ▒). */
function _openInDefaultApp(targetPath: string): { ok: boolean; message: string } {
    try {
        if (!fs.existsSync(targetPath)) {
            return { ok: false, message: `Ήκ┤ΉηυΊΧαΉπΑ ΉΧΛΈΛΦ Ά▓╜Έκε: ${targetPath}` };
        }
        if (process.platform === 'darwin') {
            spawn('open', [targetPath], { detached: true, stdio: 'ignore' }).unref();
        } else if (process.platform === 'win32') {
            spawn('cmd.exe', ['/c', 'start', '', targetPath], { detached: true, stdio: 'ignore' }).unref();
        } else {
            spawn('xdg-open', [targetPath], { detached: true, stdio: 'ignore' }).unref();
        }
        return { ok: true, message: `ΏθγΑ Ά╕░Έ│╕ ΉΧ▒Ήε╝Έκε ΉΩ┤Έο╝: ${targetPath}` };
    } catch (e: any) {
        return { ok: false, message: `ΊΝΝΉζ╝ ΉΩ┤Ά╕░ ΉΜνΊΝρ: ${e?.message || e}` };
    }
}

/**
 * Sanitize a filename: remove path separators / traversal segments / control chars.
 * Returns a safe basename (never a path) or null if nothing usable remains.
 */
function safeBasename(name: string): string | null {
    if (typeof name !== 'string') return null;
    // Drop any path components έΑΦ only the final segment is allowed.
    const base = path.basename(name).replace(/[\x00-\x1f\\/:*?"<>|]/g, '_').trim();
    if (!base || base === '.' || base === '..') return null;
    return base.slice(0, MAX_FILE_NAME_LEN);
}

/**
 * Drain an http request body with a hard size cap. Resolves to the body string,
 * or rejects with an Error("BODY_TOO_LARGE") if the cap is exceeded.
 */
function readRequestBody(req: http.IncomingMessage, maxBytes = MAX_HTTP_BODY): Promise<string> {
    return new Promise((resolve, reject) => {
        let received = 0;
        const chunks: Buffer[] = [];
        req.on('data', (chunk: Buffer) => {
            received += chunk.length;
            if (received > maxBytes) {
                reject(new Error('BODY_TOO_LARGE'));
                req.destroy();
                return;
            }
            chunks.push(chunk);
        });
        req.on('end', () => resolve(Buffer.concat(chunks).toString('utf-8')));
        req.on('error', reject);
    });
}

/**
 * Validate a remote git URL. Only http(s) and git@host:owner/repo forms are accepted.
 * Returns the cleaned URL or null when unsafe.
 */
function validateGitRemoteUrl(url: string): string | null {
    if (typeof url !== 'string') return null;
    // ΉΓυΉγσΉηΡΆ░Α ΊζΦΊηΙ Έ╢βΉΩυΈΕμΈΛΦ ΉηκΉζΝ ΉιεΆ▒░: Ά│╡Έ░▒, ΈΒζ ΉΛυΈηαΉΜε, Ή┐╝ΈουΉΛνΊΛ╕ΈπΒ/ΊΦΕΈηαΆ╖╕Έρ╝ΊΛ╕
    let trimmed = url.trim().replace(/[?#].*$/, '').replace(/\/+$/, '');
    if (!trimmed || trimmed.length > 500) return null;
    // Allowed: https://host/path, http://host/path, git@host:path  (hostΉΩΡΈΛΦ :ΊΠυΊΛ╕ ΊΩΙΉγσ)
    const httpsLike = /^https?:\/\/[A-Za-z0-9.-]+(:\d+)?\/[A-Za-z0-9._\-/]+?(\.git)?$/;
    const sshLike = /^git@[A-Za-z0-9.-]+:[A-Za-z0-9._\-/]+?(\.git)?$/;
    if (!httpsLike.test(trimmed) && !sshLike.test(trimmed)) return null;
    return trimmed;
}

/** Detect whether `git` is on PATH. Cached after first call. */
let _gitAvailableCache: boolean | null = null;
function isGitAvailable(): boolean {
    if (_gitAvailableCache !== null) return _gitAvailableCache;
    try {
        const res = spawnSync('git', ['--version'], { encoding: 'utf-8', timeout: 5000 });
        _gitAvailableCache = res.status === 0;
    } catch {
        _gitAvailableCache = false;
    }
    return _gitAvailableCache;
}

type GitErrorKind = 'auth' | 'not_found' | 'rejected' | 'merge_conflict' | 'network' | 'unknown';

/** Translate raw git stderr into a user-actionable Korean message + machine-readable kind. */
function classifyGitError(stderr: string): { kind: GitErrorKind; message: string } {
    const s = (stderr || '').toLowerCase();
    if (
        s.includes('authentication failed') ||
        s.includes('could not read username') ||
        s.includes('terminal prompts disabled') ||
        s.includes('invalid credentials') ||
        s.includes('403')
    ) {
        return {
            kind: 'auth',
            message: 'GitHub Ήζ╕ΉοζΉζ┤ ΊΧΕΉγΦΊΧ┤ΉγΦ. ΊΕ░Έψ╕ΈΕΡΉΩΡΉΕε ΊΧε Έ▓Ι `git push`Έκε ΈκεΆ╖╕Ήζ╕ ΊδΕ ΈΜνΉΜε ΉΜεΈΠΕΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.'
        };
    }
    if (s.includes('repository not found') || s.includes('does not appear to be a git repository') || s.includes('404')) {
        return { kind: 'not_found', message: 'Ά╖╕ GitHub ΉιΑΉηξΉΗΝΈξ╝ Ές╗ Ή░╛ΉΧαΉΨ┤ΉγΦ. Ήμ╝ΉΗΝΆ░Α ΉιΧΊβΧΊΧεΉπΑ ΊβΧΉζ╕ΊΧ┤Ήμ╝ΉΕ╕ΉγΦ. (Private ΉιΑΉηξΉΗΝΈσ┤ ΊΗιΊΒ░ Ά╢ΝΊΧεΈΠΕ ΊΧΕΉγΦΊΧ┤ΉγΦ)' };
    }
    if (s.includes('rejected') && (s.includes('non-fast-forward') || s.includes('fetch first'))) {
        return { kind: 'rejected', message: 'GitHubΉΩΡ ΉΔΙΈκεΉγ┤ ΈΓ┤ΉγσΉζ┤ ΉηΙΉΨ┤ΉγΦ. Έρ╝ΉιΑ Έ░δΉΧΕΉαρ ΊδΕ ΈΜνΉΜε ΉΜεΈΠΕΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.' };
    }
    if (s.includes('merge conflict') || s.includes('automatic merge failed') || s.includes('overwritten by merge')) {
        return { kind: 'merge_conflict', message: 'Ά░βΉζΑ ΉνΕΉζΕ ΉΨΣΉς╜ΉΩΡΉΕε ΈΜνΈξ┤Ά▓Ν Ά│ιΉ│ΡΉΕε ΉηΡΈΠβΉε╝Έκε ΊΧσΉ╣ι ΉΙα ΉΩΗΉΨ┤ΉγΦ. ΈΠβΆ╕░ΊβΦ ΈσΦΈΚ┤ΉΩΡΉΕε ΉπΒΉιΣ Ά│ρΈζ╝Ήμ╝ΉΕ╕ΉγΦ.' };
    }
    if (s.includes('could not resolve host') || s.includes('connection refused') || s.includes('network is unreachable') || s.includes('timed out')) {
        return { kind: 'network', message: 'Ήζ╕ΊΕ░ΈΕ╖ ΉΩ░Ά▓░ΉζΕ ΊβΧΉζ╕ΊΧ┤Ήμ╝ΉΕ╕ΉγΦ.' };
    }
    return { kind: 'unknown', message: (stderr || 'ΉΧΝ ΉΙα ΉΩΗΈΛΦ ΉανΈξα').slice(0, 240) };
}

/** Detect remote default branch ("main" / "master" / etc). Returns "main" as fallback. */
function getRemoteDefaultBranch(cwd: string): string {
    const out = gitExecSafe(['ls-remote', '--symref', 'origin', 'HEAD'], cwd, 10000);
    if (out) {
        const m = out.match(/ref:\s+refs\/heads\/([^\s]+)\s+HEAD/);
        if (m) return m[1];
    }
    return 'main';
}

/** Ensure brain folder has at least one commit so `push` has something to ship. */
function ensureInitialCommit(cwd: string) {
    if (gitExecSafe(['log', '-1'], cwd) !== null) return; // already has commits
    const placeholder = path.join(cwd, '.gitkeep');
    if (!fs.existsSync(placeholder)) fs.writeFileSync(placeholder, '');
    gitExecSafe(['add', '.'], cwd);
    // --allow-empty handles the edge case where everything is gitignored
    gitExecSafe(['commit', '--allow-empty', '-m', 'Initial brain commit'], cwd);
}

/** Auto-create a sensible .gitignore in the brain folder so junk files don't pollute the remote. */
function ensureBrainGitignore(brainDir: string) {
    const gi = path.join(brainDir, '.gitignore');
    if (fs.existsSync(gi)) return;
    const lines = [
        '# Connect AI auto-generated',
        '.DS_Store',
        '.obsidian/',
        '.trash/',
        'node_modules/',
        '*.tmp',
        '*.log',
        '.cache/',
        'Thumbs.db'
    ];
    try { fs.writeFileSync(gi, lines.join('\n') + '\n'); }
    catch { /* non-fatal */ }
}

/** Run a git subcommand and return stdout/stderr/status έΑΦ used when we need to inspect failures. */
function gitRun(args: string[], cwd: string, timeout = 30000): { status: number | null; stdout: string; stderr: string; error?: Error } {
    const res = spawnSync('git', args, {
        cwd,
        encoding: 'utf-8',
        timeout,
        env: { ...process.env, GIT_TERMINAL_PROMPT: '0' }
    });
    return {
        status: res.status,
        stdout: res.stdout || '',
        stderr: res.stderr || '',
        error: res.error
    };
}

/** Module-scoped lock so auto-sync and manual sync never run concurrently against the same brain. */
let _autoSyncRunning = false;
let _companySyncRunning = false; /* separate lock έΑΦ brain & company can sync in parallel */

/* v2.89.88 έΑΦ ΊΒυΈκεΉΛνΊΦΝΈητΊΠ╝ ΊΝΝΉζ┤ΉΞυ ΈςΖΈι╣. ΉεΙΈΠΕΉγ░ΈΛΦ `python3`Ήζ┤ Ά╕░Έ│╕ PATHΉΩΡ ΉΩΗΆ│ι
   `python`ΉζΑ Έψ╕ΉΕνΉ╣α ΉΜε MS Store ΉΛνΊΖΒΉζ┤ ΈΨιΉΕε ΉλΖΈμΝΉ╜ΦΈΥε 9009Έξ╝ ΈΓ┤Έ▒ΚΉζΝ (Python was
   not found ... ΈσΦΉΜεΉπΑ). Έπξ/ΈουΈΙΖΉΛνΈΛΦ `python3`Ήζ┤ ΊΣεΉνΑ. ΊΦΝΈητΊΠ╝Έ│ΕΈκε Έ╢ΕΆ╕░ΊΧ┤ΉΕε
   ΉειΊΛεΈ╕Ν Ή▒ΕΈΕΡ Έ╢ΕΉΕζ Ά░βΉζΑ ΈΠΕΆ╡υΆ░Α ΉεΙΈΠΕΉγ░ ΉΓυΉγσΉηΡΉΩΡΆ▓ΝΉΕε ΉΜνΊΝρΊΧαΈΞα Έυ╕Ήιε ΉΙαΉιΧ. */
function _pythonCmd(): string {
    return process.platform === 'win32' ? 'python' : 'python3';
}
/* 9009 (Windows command-not-found) ΈαΡΈΛΦ "Python was not found" ΉΛνΊΖΒ ΈσΦΉΜεΉπΑΈξ╝
   Ά░ΡΉπΑΊΧ┤ΉΕε ΈςΖΊβΧΊΧε ΊΧεΆ╡φΉΨ┤ ΉΧΙΈΓ┤Έκε Έ░ΦΆ┐ΦΉνΝ. */
function _isPythonMissing(exitCode: number, output: string): boolean {
    if (exitCode === 9009) return true;
    if (/Python was not found/i.test(output)) return true;
    if (process.platform !== 'win32' && /command not found.*python/i.test(output)) return true;
    return false;
}
function _pythonMissingHint(): string {
    return process.platform === 'win32'
        ? 'έγιΎ╕Π PythonΉζ┤ ΉΕνΉ╣αΈΡαΉΨ┤ ΉηΙΉπΑ ΉΧΛΉΛ╡ΈΜΙΈΜν. https://www.python.org/downloads/ ΉΩΡΉΕε Python 3ΉζΕ ΉΕνΉ╣αΊΧαΆ│ι ΉΕνΉ╣α ΉΜε "Add Python to PATH" Ή▓┤ΊΒυΈ░ΧΉΛνΈξ╝ Ά╝φ Ή╝εΉμ╝ΉΕ╕ΉγΦ. ΉΕνΉ╣α ΊδΕ ΉΧΙΊΜ░Ά╖╕ΈηαΈ╣ΕΊΜ░(ΈαΡΈΛΦ VS Code) ΉβΕΉιΕ ΉλΖΈμΝ έΗΤ ΉηυΉΜνΊΨΚ ΊΧΕΉγΦ.'
        : 'έγιΎ╕Π python3 ΈςΖΈι╣ΉζΕ Ή░╛ΉζΕ ΉΙα ΉΩΗΉΛ╡ΈΜΙΈΜν. ΈπξΉζΑ `brew install python3`, Ήγ░Έ╢ΕΊΙυΈΛΦ `sudo apt install python3` Έκε ΉΕνΉ╣α ΊδΕ ΉΧΙΊΜ░Ά╖╕ΈηαΈ╣ΕΊΜ░(ΈαΡΈΛΦ VS Code) ΉηυΉΜεΉηΣ.';
}

/**
 * Run a shell command and capture stdout+stderr live so the AI can act on the result.
 * - Streams output to onChunk for live display in the chat
 * - Returns combined output (capped to 15KB) + exit code
 * - Hard timeout to prevent hung processes (default 60s)
 * - Uses default shell ($SHELL or sh) for natural command parsing (npm install, cd && ls, etc.)
 */
function runCommandCaptured(
    cmd: string,
    cwd: string,
    onChunk: (text: string) => void,
    timeoutMs = 60000,
    captureStream: 'both' | 'stdout' = 'both'
): Promise<{ exitCode: number; output: string; timedOut: boolean }> {
    return new Promise((resolve) => {
        const child = spawn(cmd, {
            cwd,
            shell: true,
            env: process.env,
            stdio: ['ignore', 'pipe', 'pipe']
        });
        let buf = '';
        let timedOut = false;
        const append = (s: string) => {
            buf += s;
            // Hard cap so a runaway log never explodes memory
            if (buf.length > 30000) buf = buf.slice(-30000);
            onChunk(s);
        };
        child.stdout?.on('data', (d: Buffer) => append(d.toString()));
        /* v2.89.50 έΑΦ captureStream='stdout' Ήζ╝ ΈΧΝ stderrΈΛΦ Έυ┤ΉΜε. ΉΛνΊΒυΈο╜ΊΛ╕Ά░Α ΉπΕΊΨΚ ΈσΦΉΜεΉπΑ┬╖
           ΈκεΆ╖╕┬╖DeprecationWarningΉζΕ stderrΈκε Έ│┤ΈΓ┤ΈΠΕ Ή▒ΕΊΝΖΉ░╜ΉΩΦ ΉΧΙ ΉΔΙΉΕε Ά╣ΦΈΒΦ. */
        if (captureStream === 'both') {
            child.stderr?.on('data', (d: Buffer) => append(d.toString()));
        }
        const killTimer = setTimeout(() => {
            timedOut = true;
            /* v2.89.101 έΑΦ WindowsΈΛΦ SIGTERM/SIGKILLΉζΕ Έυ┤ΉΜεΊΧι ΉΙα ΉηΙΉζΝ. taskkill /F Έκε
               ΉηΡΉΜζ ΊΦΕΈκεΉΕ╕ΉΛν ΊΛ╕Έου ΉιΕΉ▓┤ Ά░ΧΉιε ΉλΖΈμΝ. macOS/LinuxΈΛΦ Ά╕░Ήκ┤ΈΝΑΈκε SIGTERM έΗΤ SIGKILL. */
            if (process.platform === 'win32' && child.pid) {
                try { spawn('taskkill', ['/PID', String(child.pid), '/T', '/F'], { stdio: 'ignore' }).unref(); }
                catch { try { child.kill(); } catch { /* gone */ } }
            } else {
                try { child.kill('SIGTERM'); } catch { /* already dead */ }
                setTimeout(() => { try { child.kill('SIGKILL'); } catch { /* gone */ } }, 2000);
            }
        }, timeoutMs);
        child.on('close', (code) => {
            clearTimeout(killTimer);
            resolve({ exitCode: code ?? -1, output: buf.slice(-15000), timedOut });
        });
        child.on('error', (e) => {
            clearTimeout(killTimer);
            resolve({ exitCode: -1, output: `[ΉΜνΊΨΚ ΉανΈξα] ${e.message}`, timedOut: false });
        });
    });
}

