// Settings are read from VS Code configuration (File > Preferences > Settings)
function getConfig() {
    const cfg = vscode.workspace.getConfiguration('connectAiLab');

    // ollamaUrl: only http(s)://localhost or 127.0.0.1 is meaningful here.
    let ollamaBase = (cfg.get<string>('ollamaUrl', 'http://127.0.0.1:11434') || '').trim();
    if (!/^https?:\/\//i.test(ollamaBase)) ollamaBase = 'http://127.0.0.1:11434';

    // ΉΓυΉγσΉηΡΆ░Α ΉΕιΊΔζΊΧε ΈςρΈΞ╕ΉζΑ Ά╖╕ΈΝΑΈκε ΉειΉπΑ. Έ╣Ι Ά░ΤΉζ┤Έσ┤ Έ╣Ι Έυ╕ΉηΡΉΩ┤ Έ░αΊβα έΑΦ
    // Ία╕Ή╢ε ΉΓυΉζ┤ΊΛ╕Ά░Α _autoPickInstalledModel()Έκε ΉΜνΉιε ΉΕνΉ╣αΈΡε ΈςρΈΞ╕ ΉνΣ ΊΧαΈΓαΈξ╝
    // ΉηΡΈΠβ ΉΕιΊΔζ. ΈΦΦΊΠ┤ΊΛ╕ 'gemma4:e2b' Ά░βΉζΑ ΊΒ░ ΈςρΈΞ╕ΉζΕ Ά░ΧΉιεΊΧ┤ΉΕε ΉιΑΉΓυΉΨΣ PCΆ░Α
    // Ή▓τ Ία╕Ή╢εΉΩΡΉΕε ΉΜνΊΝρΊΧαΈΞα Έυ╕Ήιε Έ░σΉπΑ.
    const defaultModel = (cfg.get<string>('defaultModel', '') || '').trim();

    // requestTimeout: clamp to [5, 1800] seconds, then convert to ms.
    const rawTimeout = cfg.get<number>('requestTimeout', 300);
    const timeoutSec = (typeof rawTimeout === 'number' && isFinite(rawTimeout))
        ? Math.min(1800, Math.max(5, rawTimeout))
        : 300;

    return {
        ollamaBase,
        defaultModel,
        maxTreeFiles: 200,
        timeout: timeoutSec * 1000,
        localBrainPath: cfg.get<string>('localBrainPath', '') || ''
    };
}

/* v2.89.91 έΑΦ ΉΩΦΉπΕ Ά░ΡΉπΑ ΊΩυΊΞ╝. Ήζ┤ΉιΕΉΩΦ `isLMStudio = ollamaBase.includes('1234')
   || ollamaBase.includes('v1')` Ά░Α 13Ά╡░ΈΞ░ ΈΠβΉζ╝ΊΧαΆ▓Ν Έ░ΧΊαΑ ΉηΙΉΩΙΉζΝ. LM StudioΆ░Α
   ΊΠυΊΛ╕ΈΓα Ά▓╜Έκε Ή╗ρΈ▓νΉΖαΉζΕ Έ░ΦΆ╛╕Έσ┤ 13Ά││ ΈςρΈΣΡ Ά│ιΉ│ΡΉΧ╝ ΊΨΙΆ│ι, ΊΧε Ά││ΉζΕ Έ╣ιΈερΈουΈσ┤
   ΈΜνΈξ╕ ΉΩΦΉπΕΉε╝Έκε Έζ╝Ήγ░ΊΝΖΈΡαΈΛΦ ΉΓυΆ│ι. ΊΧε ΊΧρΉΙαΈκε ΊΗ╡ΊΧσ. */
function _isLMStudioEngine(ollamaBase: string): boolean {
    /* v2.89.98 έΑΦ ΉπΕΉπε ΉδΡΉζ╕ ΉηκΊηα! v2.89.91 sed Ήζ╝Ά┤Ε Ή╣αΊβαΉζ┤ Ήζ┤ ΊΧρΉΙαΉζα Έ│╕Ή▓┤Ά╣ΝΉπΑ
       `_isLMStudioEngine(ollamaBase)`Έκε Έ░ΦΆ┐ΦΈ▓ΕΈιν ΉηΡΆ╕░ ΉηΡΉΜιΉζΕ Έυ┤ΊΧε Ία╕Ή╢ε έΗΤ
       Maximum call stack. ΉΓυΉγσΉηΡΆ░Α chat┬╖corp ΉΨΣΉς╜ ΈςρΈΥεΉΩΡΉΕε ΉΨ┤ΈΨν LLM Ία╕Ή╢εΈΠΕ
       Ήζ┤ ΊΩυΊΞ╝Έξ╝ Ά▒░Ή╣αΈΜΙ ΉιΕ Έζ╝Ήζ╕Ήζ┤ ΈπΙΈ╣ΕΈΡΡΉΩΙΉζΝ. ΉδΡΈηα ΈκεΉπΒ Έ│╡ΉδΡ: 1234 ΊΠυΊΛ╕ ΈαΡΈΛΦ
       /v1 Ά▓╜ΈκεΈσ┤ LM Studio. */
    return ollamaBase.includes('1234') || ollamaBase.includes('v1');
}

/* v2.89.66 έΑΦ _getBrainDir, _isBrainDirExplicitlySet, getCompanyDir, COMPANY_SUBDIR,
   _expandTilde, _resolvePathInput ΈςρΈΣΡ ./paths.ts Έκε Ήζ┤ΈΠβ. ΈςρΈΥΙ Ά░Ε import Ήζ╝ΉδΡΊβΦ. */
import { _getBrainDir, _isBrainDirExplicitlySet, getCompanyDir, COMPANY_SUBDIR, _expandTilde, _resolvePathInput } from './paths';

async function _ensureBrainDir(): Promise<string | null> {
    if (_isBrainDirExplicitlySet()) {
        return _getBrainDir();
    }
    // ΊΠ┤ΈΞΦ Έψ╕ΉΕνΉιΧ έΗΤ ΉΓυΉγσΉηΡΉΩΡΆ▓Ν Ά░ΧΉιε ΉΕιΊΔζ ΉγΦΉ▓φ
    const result = await vscode.window.showInformationMessage(
        'ΏθΥΒ ΉπΑΉΜζΉζΕ ΉιΑΉηξΊΧι ΊΠ┤ΈΞΦΈξ╝ Έρ╝ΉιΑ ΉΕιΊΔζΊΧ┤Ήμ╝ΉΕ╕ΉγΦ! (AIΆ░Α ΈΜ╡Έ│ΑΊΧι ΈΧΝ Ή░╕Ά│ιΊΧι .md ΊΝΝΉζ╝ΈΥνΉζ┤ Έ│┤Ά┤ΑΈΡσΈΜΙΈΜν)',
        'ΊΠ┤ΈΞΦ ΉΕιΊΔζΊΧαΆ╕░'
    );
    if (result !== 'ΊΠ┤ΈΞΦ ΉΕιΊΔζΊΧαΆ╕░') return null;
    
    const folders = await vscode.window.showOpenDialog({
        canSelectFolders: true, canSelectFiles: false, canSelectMany: false,
        openLabel: 'Ήζ┤ ΊΠ┤ΈΞΦΈξ╝ ΈΓ┤ ΉπΑΉΜζ ΊΠ┤ΈΞΦΈκε ΉΓυΉγσ',
        title: 'Ώθπι ΈΓ┤ ΉπΑΉΜζ ΊΠ┤ΈΞΦ ΉΕιΊΔζ'
    });
    if (!folders || folders.length === 0) return null;
    
    const selectedPath = folders[0].fsPath;
    await vscode.workspace.getConfiguration('connectAiLab').update('localBrainPath', selectedPath, vscode.ConfigurationTarget.Global);
    vscode.window.showInformationMessage(`έεΖ ΉπΑΉΜζ ΊΠ┤ΈΞΦΆ░Α ΉΕνΉιΧΈΡαΉΩΙΉΨ┤ΉγΦ: ${selectedPath}`);
    return selectedPath;
}

