/* v2.89.61 έΑΦ 9Ά░ε LLM ΊΦΕΈκυΊΦΕΊΛ╕(SYSTEM, CEO_*, SECRETARY_*) Έξ╝ assets/prompts/ ΉΩΡ .md
   ΊΝΝΉζ╝Έκε Έ╢ΕΈου. Ήζ╡ΉΛνΊΖΡΉΖα ΈκεΈΥε ΉΜε ΊΧε Έ▓Ι Ήζ╜ΉΨ┤ ΈσΦΈςρΈουΉΩΡ Ή║ΡΉΜε. ΊΦΕΈκυΊΦΕΊΛ╕ ΉΙαΉιΧΉζ┤ Ή╜ΦΈΥε
   ΉΙαΉιΧ ΉΩΗΉζ┤ Ά░ΑΈΛξ + ΉνΕ ΉΙα 287ΉνΕ ΉιΙΉΧ╜ + IDEΉΩΡΉΕε markdown Έψ╕ΈουΈ│┤Ά╕░Έκε Ά▓ΑΊΗι Ά░ΑΈΛξ.
   __dirnameΈΛΦ esbuild Έ▓ΙΈΥν Ή╢εΈιξ ΉεΕΉ╣α(extension/out)Ήζ┤Έζ╝ ../assets/prompts Έκε ΊΧε ΈΜρΆ│Ε ΉεΕ. */
const _PROMPTS_DIR = path.join(__dirname, '..', 'assets', 'prompts');
const _promptCache = new Map<string, string>();
function _loadPrompt(file: string): string {
    let cached = _promptCache.get(file);
    if (cached !== undefined) return cached;
    try {
        cached = fs.readFileSync(path.join(_PROMPTS_DIR, file), 'utf-8');
    } catch (e: any) {
        console.error(`[Connect AI] prompt ΈκεΈΥε ΉΜνΊΝρ ${file}:`, e?.message || e);
        cached = '';
    }
    _promptCache.set(file, cached);
    return cached;
}

/* v2.89.62 έΑΦ 11Ά░ε Python ΈΠΕΆ╡υ + 11Ά░ε README Έξ╝ assets/tool-seeds/<agent>/<tool>.{py,md} Έκε Έ╢ΕΈου.
   Ά░Β _seed* ΊΧρΉΙαΉΩΡΉΕε lazy load. assets/tool-seeds/secretary/telegram_setup.py Ά░βΉζΑ ΊαΧΊΔε. */
const _TOOL_SEEDS_DIR = path.join(__dirname, '..', 'assets', 'tool-seeds');
const _toolSeedCache = new Map<string, string>();
function _loadToolSeed(rel: string): string {
    let cached = _toolSeedCache.get(rel);
    if (cached !== undefined) return cached;
    try {
        cached = fs.readFileSync(path.join(_TOOL_SEEDS_DIR, rel), 'utf-8');
    } catch (e: any) {
        console.error(`[Connect AI] tool seed ΈκεΈΥε ΉΜνΊΝρ ${rel}:`, e?.message || e);
        cached = '';
    }
    _toolSeedCache.set(rel, cached);
    return cached;
}

