/* JSON ΉΜεΈΥε ΊΝΝΉζ╝ΉΩΡ ΉΔΙ _schemaΈξ╝ Έρ╕ΉπΑ. ΉΓυΉγσΉηΡΆ░Α ΉηΖΈιξΊΧε Ά░ΤΉζΑ ΉιΙΈΝΑ Ά▒┤ΈΥεΈουΉπΑ ΉΧΛΆ│ι,
   _schemaΈπΝ ΊΧφΉΔΒ Ή╡εΉΜιΉε╝Έκε Ά░▒ΉΜι. freshΉΩΡ ΉΔΙΈκε Ή╢ΦΆ░ΑΈΡε ΊΓνΈΛΦ Έ╣Ι Ά░ΤΉε╝Έκε Ή╢ΦΆ░ΑΊΧαΆ│ι,
   existingΉΩΡΈπΝ ΉηΙΈΛΦ ΊΓνΈΠΕ Έ│┤Ήκ┤ (ΉαΙ: ΈΓαΉνΣΉΩΡ OAuth flowΆ░Α Ή╢ΦΆ░ΑΊΧε ΊΗιΊΒ░). */
function _mergeSchemaIntoJson(p: string, freshJson: string) {
  if (!fs.existsSync(p)) {
    fs.writeFileSync(p, freshJson);
    return;
  }
  try {
    const fresh = JSON.parse(freshJson);
    const existing = JSON.parse(fs.readFileSync(p, 'utf-8') || '{}');
    /* 1) existingΉζα ΈςρΈΥι ΊΓν Ά╖╕ΈΝΑΈκε Έ│┤Ήκ┤ (OAuth ΊΗιΊΒ░Ή▓αΈθ╝ ΈΠβΉιΒΉε╝Έκε Ή╢ΦΆ░ΑΈΡε Ά░Τ ΊΠυΊΧρ) */
    const merged: Record<string, any> = { ...existing };
    /* 2) freshΉΩΡΈπΝ ΉηΙΈΛΦ ΉΔΙ ΊΓνΈΛΦ Έ╣Ι Ά░ΤΉε╝Έκε Ή╢ΦΆ░Α */
    for (const k of Object.keys(fresh)) {
      if (k === '_schema') continue;
      if (!(k in merged)) merged[k] = fresh[k];
    }
    /* 3) _schemaΈΛΦ ΊΧφΉΔΒ Ή╡εΉΜι freshΈκε ΈΞχΉΨ┤ΉΥ░Ά╕░ (ΉΓυΉγσΉηΡΆ░Α ΊΟ╕ΉπΣΊΧαΉπΑ ΉΧΛΈΛΦ ΈσΦΊΔΑ) */
    merged['_schema'] = fresh['_schema'];
    fs.writeFileSync(p, JSON.stringify(merged, null, 2));
  } catch {
    fs.writeFileSync(p, freshJson);
  }
}

/* έΦΑέΦΑέΦΑ My Videos Check έΑΦ own channel performance (pro_v1) έΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑ
   v2.89.43 έΑΦ ΉιΕΈυ╕ ΉειΊΛεΈ╕Ν Έ╢ΕΉΕζΆ░Α ΉΙαΉνΑΉζα ΉλΖΊΧσ Έ│┤Ά│ιΉΕε. Ήζ┤ΉιΕΉΩΦ ΉνΣΆ░ΕΆ░Τ 1ΉνΕ + ΉαΒΉΔΒ ΈςσΈκζΈπΝ
   Ή╢εΈιξΊΧ┤ΉΕε "ΉιΕΈυ╕ ΉΩΡΉζ┤ΉιΕΊΛ╕ΈΜ╡ΉπΑ Ές╗ΊΧρ"Ήζ┤Έζ╝ΈΛΦ ΉΓυΉγσΉηΡ ΊΦ╝ΈΥεΈ░▒. Ήζ┤Ήιε Ή▒ΕΈΕΡ ΈσΦΊΔΑ┬╖ΉγΦΉζ╝Έ│Ε ΉΕ▒Ά│╝┬╖
   Ή░╕ΉΩυΉερ┬╖ΉιεΈςσ ΊΓνΉδΝΈΥε┬╖Ήζ╕Ά╕░ ΈΝΥΆ╕Α┬╖Ά╡υΉ▓┤ ΉΧκΉΖα Ή╢ΦΉ▓εΆ╣ΝΉπΑ ΊΠυΊΧρ. */
function _seedYouTubeMyVideosCheck(toolsDir: string) {
  const py = _loadToolSeed('youtube/my_videos_check.py');
  const json = JSON.stringify({ LOOKBACK_DAYS: 30, TOP_N: 15, COMMENT_SAMPLES: 5 }, null, 2);
  const md = _loadToolSeed('youtube/my_videos_check.md');
  /* Force-upgrade the .py έΑΦ older users on pre-telegram_v2 versions need
     the Secretary fallback so token doesn't have to be duplicated. */
  /* v2.89.43 έΑΦ sentinel 'pro_v1' = ΉλΖΊΧσ Έ╢ΕΉΕζ Έ▓ΕΉιΕ. Ά╕░Ήκ┤ ΉΓυΉγσΉηΡΈΠΕ ΉηΡΈΠβ ΉΩΖΆ╖╕ΈιΙΉζ┤ΈΥε. */
  /* sentinel pro_v4 έΑΦ HTML entity ΈΦΦΉ╜ΦΈΥε + Έ╣Ι ΉαΒΉΔΒ ΉΜε stderrΈκε. Ά╕░Ήκ┤ ΉΕνΉ╣αΉηΡ ΉηΡΈΠβ ΉΩΖΆ╖╕ΈιΙΉζ┤ΈΥε. */
  _seedFileForceUpgrade(path.join(toolsDir, 'my_videos_check.py'), py, 'pro_v4');
  _seedFile(path.join(toolsDir, 'my_videos_check.json'), json);
  /* v2.89.20 έΑΦ Force upgrade .md heading from old "ΈΓ┤ ΉαΒΉΔΒ Ή▓┤ΊΒυ" to "ΈΓ┤ ΉειΊΛεΈ╕Ν Ή▒ΕΈΕΡ Έ╢ΕΉΕζ"
     for existing users. Sentinel = the new heading text. */
  _seedFileForceUpgrade(path.join(toolsDir, 'my_videos_check.md'), md, 'ΈΓ┤ ΉειΊΛεΈ╕Ν Ή▒ΕΈΕΡ Έ╢ΕΉΕζ');
}

