let _dashboardExtensionUri: vscode.Uri | null = null;

/* v2.89.60 έΑΦ Webview ΉιΧΉιΒ ΉηΡΉΓ░ ΈκεΈΞΦ. CSS┬╖JS ΊΖεΊΦΝΈο┐Ήζ┤ ΈΕΙΈυ┤ Ή╗νΉι╕ΉΕε (1,500+ ΉνΕ) ΊΝΝΉζ╝ Έ╢ΕΈου.
   Ά░Β _html()ΉΩΡΉΕε ${_loadWebviewAsset('dashboard.css')} ΊαΧΊΔεΈκε ΉΓυΉγσ. activate() Ήζ┤ΊδΕΉΩΡΈπΝ
   ΈΠβΉηΣ έΑΦ _dashboardExtensionUri ΉΕνΉιΧΈΡαΆ╕░ ΉιΕΉΩΦ Έ╣Ι Έυ╕ΉηΡΉΩ┤ Έ░αΊβα (fail-safe). */
function _loadWebviewAsset(name: string): string {
    if (!_dashboardExtensionUri) return '';
    try {
        const p = path.join(_dashboardExtensionUri.fsPath, 'assets', 'webview', name);
        return fs.readFileSync(p, 'utf-8');
    } catch (e: any) {
        console.warn(`[Connect AI] webview asset ΈκεΈΥε ΉΜνΊΝρ ${name}:`, e?.message || e);
        return '';
    }
}

/* έΦΑέΦΑ Unified API Connections panel (v2.85) έΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑ
   Single full-screen webview where the user fills all integration credentials
   (Telegram bot, YouTube Data API, Google Calendar, etc.) in one place.
   Reads/writes the existing per-agent `config.md` files so this panel is
   purely a friendlier UI on top of the same source of truth έΑΦ no schema
   changes, fully compatible with manual editing. */
interface ApiServiceField {
    key: string;
    label: string;
    type: 'text' | 'password';
    placeholder?: string;
    help?: string;
}
interface ApiServiceDef {
    id: string;
    name: string;
    icon: string;
    summary: string;
    helpUrl?: string;
    /* `_agents/<agentId>/config.md` is where the values land. */
    agentId: string;
    fields: ApiServiceField[];
    /* Optional command to launch a guided OAuth wizard (e.g. Google Calendar). */
    wizardCommand?: string;
    /* When true, the service shows as "ΉνΑΈ╣Ε ΉνΣ" έΑΦ fields disabled, no save. */
    comingSoon?: boolean;
}

